	if( ! $post_id ) die;

	$post = get_post( $post_id );
	if( ! $post ) die;

	$meta = get_post_meta( $post->ID, '_enable_sidebar', true );

	if ( $meta == 'yes' ) {
		update_post_meta($post->ID, '_enable_sidebar', 'no' );
