		update_post_meta($post->ID, '_enable_sidebar', 'yes' );
	}

	$sendback = remove_query_arg( array( 'trashed', 'untrashed', 'deleted', 'ids' ), wp_get_referer() );
	wp_safe_redirect( $sendback );
} // End enable_custom_post_sidebars()

